from agent import *from models.products import *import simplejsonXCAT = ['Wohnbereiche', 'Wohnideen', 'SALE', 'Marken', 'Prospekte', 'Gutscheine', 'Wohnbereiche', 'Küchenstudio', 'Planung und Beratung']def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=9000)]    session.queue(Request('https://www.roller.de/', max_age=0), process_frontpage, dict())def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//div[contains(@class, "Main-nav-item")]')    for cat in cats:        name = cat.xpath('a/text()').string()        if name not in XCAT:            cats1 = cat.xpath('.//div[@class="h3"]/a')            for cat1 in cats1:                name1 = cat1.xpath('text()').string()                url = cat1.xpath('@href').string()                if name1 not in XCAT:                    session.queue(Request(url, max_age=0), process_subcategory, dict(cat=name+'|'+name1))def process_subcategory(data, context, session):    strip_namespace(data)    subcats = data.xpath('//a[@data-id="main-category-card" or @data-v-76982744="data-v-76982744"]')    if not subcats:        cat = data.response_url.strip('/').split('/')[-1]        url = 'https://www.roller.de/api/category/' + cat + '/products?sort=topRated'        session.queue(Request(url, force_charset='utf-8', max_age=0), process_prodlist, dict(context, cat_url=url))        return    for subcat in subcats:        name = subcat.xpath('span//p/text()[normalize-space()]').string().replace('Kategorie ', '')        url = subcat.xpath('@href').string()        if name not in XCAT:            session.queue(Request(url, max_age=0), process_subcategory, dict(cat=context['cat'] + '|' + name))def process_prodlist(data, context, session):    prods_json = simplejson.loads(data.content)    prods = prods_json.get('products', [])    for prod in prods:        product = Product()        product.name = prod.get('name')        product.manufacturer = prod.get('brandName')        product.category = context['cat']        product.ssid = str(prod['code'])        product.sku = product.ssid        product.url = 'https://www.roller.de/' + product.ssid        revs_cnt = prod.get('rating', {}).get('count')        if revs_cnt and revs_cnt > 0:            revs_url = 'https://www.roller.de/api/products/' + product.ssid + '/reviews?page=0'            session.queue(Request(revs_url, max_age=0), process_reviews, dict(product=product))    next_page = context.get('page', 0) + 1    last_page = prods_json.get('pagination', {}).get('totalPages')    if next_page < last_page:        next_url = context['cat_url'] + '&page=' + str(next_page)        session.queue(Request(next_url, force_charset='utf-8', max_age=0), process_prodlist, dict(context, page=next_page))def process_reviews(data, context, session):    product = context.get('product')    revs_json = simplejson.loads(data.content)    revs = revs_json.get('comments', [])    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        review.ssid = str(rev.get('id'))        # no author        date = rev.get('date')        if date:            review.date = date.split('T')[0]        grade_overall = rev.get('rating')        if grade_overall and grade_overall > 0:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        excerpt = rev.get('comment')        if excerpt:            excerpt = excerpt.replace('\n', '').strip(' ,=+-"*\n')            if excerpt and len(excerpt) > 2:                review.add_property(type='excerpt', value=excerpt)                product.reviews.append(review)    next_page = context.get('page', 0) + 1    last_page = revs_json.get('totalPages')    if next_page < last_page:        next_url = 'https://www.roller.de/api/products/' + product.ssid + '/reviews?page=' + str(next_page)        session.do(Request(next_url, max_age=0), process_reviews, dict(product=product, page=next_page))    elif product.reviews:        session.emit(product)